const results = [];
const seen = new Set();

function normalizePhone(p) {
  if (!p) return '';
  const d = p.replace(/[^\d]/g, '');
  if (d.length === 11 && d.startsWith('0')) return '+98' + d.slice(1);
  if (d.length === 10) return '+98' + d;
  if (d.length === 12 && d.startsWith('98')) return '+' + d;
  return p;
}

for (const item of $input.all()) {
  const d = item.json;
  const tags = d.tags || d.extratags || {};

  if (d.display_name) {
    const name = (d.namedetails && (d.namedetails['name:fa'] || d.namedetails.name)) ||
                 d.display_name.split(',')[0].trim();
    if (!name) continue;
    const key = name.toLowerCase() + '|' + (d.lat || '');
    if (seen.has(key)) continue;
    seen.add(key);
    results.push({
      name,
      category: d.type || d.class || tags.amenity || tags.shop || '',
      address: d.display_name || '',
      city: (d.address && (d.address.city || d.address.town || d.address.village)) || '',
      province: (d.address && d.address.state) || '',
      website: tags.website || tags['contact:website'] || '',
      phone: normalizePhone(tags.phone || tags['contact:phone'] || ''),
      rating: '',
      latitude: d.lat || '',
      longitude: d.lon || '',
      source: 'osm-nominatim'
    });
  } else if (d.type === 'node' || d.type === 'way') {
    const name = tags['name:fa'] || tags.name || '';
    if (!name) continue;
    const lat = d.lat || (d.center && d.center.lat) || '';
    const key = name.toLowerCase() + '|' + lat;
    if (seen.has(key)) continue;
    seen.add(key);
    results.push({
      name,
      category: tags.amenity || tags.shop || tags.tourism || '',
      address: [tags['addr:street'], tags['addr:housenumber'], tags['addr:city']].filter(Boolean).join(', '),
      city: tags['addr:city'] || '',
      province: tags['addr:province'] || '',
      website: tags.website || tags['contact:website'] || '',
      phone: normalizePhone(tags.phone || tags['contact:phone'] || ''),
      rating: '',
      latitude: lat,
      longitude: d.lon || (d.center && d.center.lon) || '',
      source: 'overpass'
    });
  }
}

return [{ json: { results, total: results.length } }];
